Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                        <Label Text="{Binding Name}" FontAttributes="Bold" />
                        <Label Text="{Binding Description}" FontSize="12"
                               TextColor="{StaticResource Gray500}" />
                    </VerticalStackLayout>
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false;   // Must set false or spinner hangs
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;   // Clear so re-selecting the same item works
    }
}
```

### Key binding points

| XAML property | ViewModel property | Notes |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Set `false` when done or spinner hangs |
| `RefreshView.Command` | `RefreshCommand` | Reloads data from API |
| `CollectionView.ItemsSource` | `Items` (ObservableCollection) | Must be `ObservableCollection<T>`, not `List<T>` |
| `CollectionView.SelectedItem` | `SelectedItem` (**TwoWay**) | Null it after navigation so the same item can be re-selected |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires on tap; navigates to detail page |

### Important details

- **`RefreshView` wraps `CollectionView`** — pull-to-refresh is not built into CollectionView itself.
- **Set `IsRefreshing = false`** in a `finally` block so the spinner always stops.
- **Clear `SelectedItem`** after navigation — otherwise tapping the same item again won't trigger selection.
- **Use `x:DataType`** on the `DataTemplate` for compiled bindings and better performance.
- **Never use `ViewCell`** — use `Grid`, `StackLayout`, or any `View` as the template root.
